            val sanitizedParams = sanitizeParameters(parameters)
            
            val message = "DB_QUERY: $sanitizedQuery"
            Timber.tag(TAG).v(message)
            
            if (sanitizedParams != null) {
                Timber.tag(TAG).v("DB_PARAMS: $sanitizedParams")
            }
        }
        
        fun logApiRequest(
            url: String,
            method: String,
            headers: Map<String, String>?,
            body: String?
        ) {
            val requestId = "REQ-${System.currentTimeMillis()}"
            loggedRequests[requestId] = System.currentTimeMillis()
            
            val sanitizedUrl = sanitizeUrl(url)
            val sanitizedHeaders = sanitizeHeaders(headers)
            
            Timber.tag(TAG).v("API_REQUEST: $method $sanitizedUrl")
            
            if (sanitizedHeaders != null) {
                Timber.tag(TAG).v("API_HEADERS: $sanitizedHeaders")
            }
            
            if (body != null && body.isNotEmpty()) {
