class AppLoggingTree : Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        when (priority) {
            Log.VERBOSE -> Log.v(tag, message)
            Log.DEBUG -> Log.d(tag, message)
            Log.INFO -> Log.i(tag, message)
            Log.WARN -> Log.w(tag, message)
            Log.ERROR -> Log.e(tag, message)
            Log.ASSERT -> Log.wtf(tag, message)
        }
        
        if (t != null) {
            Log.e(tag, "Exception occurred", t)
        }
    }
}

class HttpLoggingInterceptorWrapper : HttpLoggingInterceptor() {
    init {
        level = HttpLoggingInterceptor.Level.BODY
    }
    
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val response = chain.proceed(request)
        
        ComprehensiveLogger.logApiRequest(
            url = request.url.toString(),
            method = request.method,
            headers = request.headers.toMap(),
            body = request.body?.let { 
                val buffer = okio.Buffer()
                it.writeTo(buffer)
                buffer.readUtf8()
            }
        )
        
        ComprehensiveLogger.logApiResponse(
            url = response.request.url.toString(),
            statusCode = response.code,
            headers = response.headers.toMap(),
            body = response.body?.string()
        )
        
        return response
    }
